    const nx = x + dx;
    const ny = y + dy;
    if (live.has(cellKey([nx, ny]))) {
      liveNeighborCount++;
    } else {
      const deadKey = cellKey([nx, ny]);
      if (!checkedDead.has(deadKey)) {
        checkedDead.add(deadKey);
        deadNeighbors.push([nx, ny]);
      }
    }
  }

